    if not node:
        return Node(char)
    if char < node.char:
        node.left = process_char(char, node.left)
    elif char > node.char:
        node.right = process_char(char, node.right)
    return node

def build_bst(sequence):
    root = None
    for char in sequence:
        root = process_char(char, root)
    return root

